import React, { useState } from "react";
import {Link,Routes, Route, Navigate, BrowserRouter} from 'react-router-dom';
import './Design.css';

function Homepage(){
return<>

<div class="topnav">
<a className="pad" id="">Curtain Gifts</a> 
        <a id="productHomeButton"> <Link to = "/home" className="link"> Home  </Link> </a>
        <a id="productCartButton"> < Link to = "/user/cart" className="link"> Cart </Link> </a>
        <a id="productOrderButton"> < Link to = "/user/orders" className="link"> Orders </Link> </a>
<a className="padr"> < Link to = "/login" className="link">Logout</Link></a>
</div> 

<div style={{ float:"Left",width:"56%", margin:"10px"}}>
        <br/>
        <div className="ScrollStyle">
            <div>
            {gifts.map(gift => {
            return(
                <div> 
                    < div className="box" id = {gift.id}> 
                    {gift.imageURL}
                    <t/>                  
                    {gift.giftName} 
                    <t/>
                    {gift.giftPrice}
                    <t/>
                    {gift.giftQuantity}
                    <t/>
                    {gift.giftDesc}
                    <t/>
                   <button onClick={()=>toUpdate(gift.id)}> Edit </button>
                <button onClick={()=>redirect(gift.id)}> Delete </button>
                    </div>
                <br/>
                </div>
            )
        })}
            </div>
        </div>
    </div>
</>

}
export default Homepage;
